1	//! Route model for the interactive web UI.
2	//!
3	//! Every observed request path has the shape
4	//! `/thy/<theory-kind>/<index>/<handler>/<args…>` where:
5	//! * `<theory-kind>` is the analysis kind — only `trace` appears in the corpus
6	//!   (a `diff` kind is plausible but unobserved).
7	//! * `<index>` is either `#` (the "current" theory version) or a decimal number.
8	//! * `<handler>` selects the response family. Observed handlers and their
9	//!   response `kind`:
10	//!     - `main/…`                    -> JSON envelope (`{html,title}` / `{redirect}`)
11	//!     - `overview/…`                -> full-page HTML
12	//!     - `intdot/…`                  -> HTML mini-page
13	//!     - `interactive-graph-def/…`   -> DOT
14	//!     - `next/…`, `prev/…`          -> text (a navigation URL)
15	//!     - `autoprove/…`               -> JSON (`{redirect}`), or text on timeout
16	//!     - `source`, `message`         -> text (theory source)
17	//!
18	//! Under `main`, the sub-handlers are: `help`, `message`, `rules`, `tactic`,
19	//! `cases/{raw|refined}/{level}/{n}`, `lemma/{name}`, `add/{pos}`,
20	//! `edit/{name}`, `delete/{name}`, `method/{lemma}/{n}`, and
21	//! `proof/{lemma}/{path…}` (the proof path is a sequence of case-name segments,
22	//! the root being `_`).
23	//!
24	//! This module parses a path into a structured value; it is descriptive (the
25	//! route grammar as observed), not a dispatcher.
26	
27	/// Theory version selector.
28	#[derive(Debug, PartialEq, Eq, Clone)]
29	pub enum Index {
30	    /// `#` — the server's "current" theory version.
31	    Current,
32	    /// An explicit decimal version index.
33	    Num(u64),
34	}
35	
36	impl Index {
37	    fn parse(s: &str) -> Option<Index> {
38	        if s == "#" {
39	            Some(Index::Current)
40	        } else {
41	            s.parse::<u64>().ok().map(Index::Num)
42	        }
43	    }
44	}
45	
46	/// A `main/*` sub-handler.
47	#[derive(Debug, PartialEq, Eq, Clone)]
48	pub enum Main {
49	    Help,
50	    Message,
51	    Rules,
52	    Tactic,
53	    Cases { refined: bool, level: usize, n: usize },
54	    Lemma(String),
55	    Add(String),
56	    Edit(String),
57	    Delete(String),
58	    /// Apply proof method `n` at the node identified by `path` (a `/`-joined
59	    /// sequence of case-name segments, root `_`). The method number precedes the
60	    /// path in the URL: `method/{lemma}/{n}[/path…]` (observed live [L8] and in
61	    /// 67988 body links [Q032]).
62	    Method { lemma: String, n: usize, path: Vec<String> },
63	    Proof { lemma: String, path: Vec<String> },
64	    /// Observational-equivalence proof view (`main/diffProof/{lemma}[/path…]`),
65	    /// the diff-mode analogue of `Proof`.
66	    DiffProof { lemma: String, path: Vec<String> },
67	    /// Apply a diff proof method (`main/diffMethod/{lemma}/{n}[/path…]`), the
68	    /// diff-mode analogue of `Method`.
69	    DiffMethod { lemma: String, n: usize, path: Vec<String> },
70	    /// The diff construction/deconstruction rules view (`main/diffrules`).
71	    DiffRules,
72	    /// Any unrecognized `main/*` tail.
73	    Other(Vec<String>),
74	}
75	
76	/// The selected handler and its arguments.
77	#[derive(Debug, PartialEq, Eq, Clone)]
78	pub enum Handler {
79	    Source,
80	    Message,
81	    Main(Main),
82	    Overview(Vec<String>),
83	    Intdot(Vec<String>),
84	    InteractiveGraphDef(Vec<String>),
85	    Next(Vec<String>),
86	    Prev(Vec<String>),
87	    Autoprove(Vec<String>),
88	    /// Autoprove a single diff lemma (`autoproveDiff/{strategy}/{bound}/diffProof/…`).
89	    AutoproveDiff(Vec<String>),
90	    /// Autoprove all lemmas (`autoproveAll/{strategy}/{bound}`).
91	    AutoproveAll(Vec<String>),
92	    /// Re-read the theory from disk in place (`reload`; POST).
93	    Reload,
94	    /// Download the theory source (`download/{file}`; GET). The filename is a
95	    /// decorative URL segment — the body is always the current theory's source.
96	    Download(String),
97	    /// Append modified lemmas to the on-disk file (`get_and_append/{file}`; POST).
98	    GetAndAppend(String),
99	    /// A structural-edit form target (`edit/{verb}/{name}`; POST). The tail is the
100	    /// `{verb}/{name}` remainder.
101	    Edit(Vec<String>),
102	    /// Unrecognized handler with its raw tail.
103	    Other { name: String, tail: Vec<String> },
104	}
105	
106	/// A parsed route.
107	#[derive(Debug, PartialEq, Eq, Clone)]
108	pub struct Route {
109	    pub theory_kind: String,
110	    pub index: Index,
111	    pub handler: Handler,
112	}
113	
114	fn owned(v: &[&str]) -> Vec<String> {
115	    v.iter().map(|s| s.to_string()).collect()
116	}
117	
118	fn parse_main(tail: &[&str]) -> Main {
119	    match tail {
120	        ["help"] => Main::Help,
121	        ["message"] => Main::Message,
122	        ["rules"] => Main::Rules,
123	        ["diffrules"] => Main::DiffRules,
124	        ["tactic"] => Main::Tactic,
125	        ["cases", kind, level, n]
126	            if (*kind == "raw" || *kind == "refined")
127	                && level.parse::<usize>().is_ok()
128	                && n.parse::<usize>().is_ok() =>
129	        {
130	            Main::Cases {
131	                refined: *kind == "refined",
132	                level: level.parse().unwrap(),
133	                n: n.parse().unwrap(),
134	            }
135	        }
136	        ["lemma", name] => Main::Lemma((*name).to_string()),
137	        ["add", pos] => Main::Add((*pos).to_string()),
138	        ["edit", name] => Main::Edit((*name).to_string()),
139	        ["delete", name] => Main::Delete((*name).to_string()),
140	        ["method", lemma, n, rest @ ..] if n.parse::<usize>().is_ok() => Main::Method {
141	            lemma: (*lemma).to_string(),
142	            n: n.parse().unwrap(),
143	            path: owned(rest),
144	        },
145	        ["diffMethod", lemma, n, rest @ ..] if n.parse::<usize>().is_ok() => Main::DiffMethod {
146	            lemma: (*lemma).to_string(),
147	            n: n.parse().unwrap(),
148	            path: owned(rest),
149	        },
150	        ["diffProof", lemma, rest @ ..] => Main::DiffProof {
151	            lemma: (*lemma).to_string(),
152	            path: owned(rest),
153	        },
154	        [proof, lemma, rest @ ..] if *proof == "proof" => Main::Proof {
155	            lemma: (*lemma).to_string(),
156	            path: owned(rest),
157	        },
158	        _ => Main::Other(owned(tail)),
159	    }
160	}
161	
162	impl Route {
163	    /// Parse a request path such as `/thy/trace/#/main/proof/exec/_/B_2`.
164	    /// Returns `None` if the path is not under `/thy/<kind>/<index>/…`.
165	    pub fn parse(path: &str) -> Option<Route> {
166	        let trimmed = path.strip_prefix('/').unwrap_or(path);
167	        let segs: Vec<&str> = trimmed.split('/').collect();
168	        // Need at least: thy / kind / index / handler
169	        if segs.len() < 4 || segs[0] != "thy" {
170	            return None;
171	        }
172	        let theory_kind = segs[1].to_string();
173	        let index = Index::parse(segs[2])?;
174	        let handler_name = segs[3];
175	        let tail = &segs[4..];
176	        let handler = match handler_name {
177	            "source" => Handler::Source,
178	            "message" => Handler::Message,
179	            "main" => Handler::Main(parse_main(tail)),
180	            "overview" => Handler::Overview(owned(tail)),
181	            "intdot" => Handler::Intdot(owned(tail)),
182	            "interactive-graph-def" => Handler::InteractiveGraphDef(owned(tail)),
183	            "next" => Handler::Next(owned(tail)),
184	            "prev" => Handler::Prev(owned(tail)),
185	            "autoprove" => Handler::Autoprove(owned(tail)),
186	            "autoproveDiff" => Handler::AutoproveDiff(owned(tail)),
187	            "autoproveAll" => Handler::AutoproveAll(owned(tail)),
188	            "reload" => Handler::Reload,
189	            "download" => match tail {
190	                [file] => Handler::Download((*file).to_string()),
191	                _ => Handler::Other { name: "download".to_string(), tail: owned(tail) },
192	            },
193	            "get_and_append" => match tail {
194	                [file] => Handler::GetAndAppend((*file).to_string()),
195	                _ => Handler::Other { name: "get_and_append".to_string(), tail: owned(tail) },
196	            },
197	            "edit" => Handler::Edit(owned(tail)),
198	            other => Handler::Other {
199	                name: other.to_string(),
200	                tail: owned(tail),
201	            },
202	        };
203	        Some(Route {
204	            theory_kind,
205	            index,
206	            handler,
207	        })
208	    }
209	}
210	
211	/// The full request surface: the top-level (non-`/thy`) routes plus the
212	/// theory-scoped `/thy/<kind>/<index>/…` routes.
213	///
214	/// `Toplevel::parse` takes the URL **path** only (any `?query` must be split off
215	/// by the caller and passed separately to the dispatcher).
216	#[derive(Debug, PartialEq, Eq, Clone)]
217	pub enum Toplevel {
218	    /// `/` — the index page (GET) / theory upload (POST).
219	    Root,
220	    /// `/robots.txt`.
221	    Robots,
222	    /// `/favicon.ico` — a `303` redirect to the static icon.
223	    Favicon,
224	    /// `/kill` — cancel a running proof search (requires a `path` query arg).
225	    Kill,
226	    /// `/static/<path…>` — a filesystem-backed asset.
227	    Static(Vec<String>),
228	    /// A theory-scoped route.
229	    Thy(Route),
230	    /// Anything else (→ 404).
231	    Other(String),
232	}
233	
234	impl Toplevel {
235	    pub fn parse(path: &str) -> Toplevel {
236	        let trimmed = path.strip_prefix('/').unwrap_or(path);
237	        if trimmed.is_empty() {
238	            return Toplevel::Root;
239	        }
240	        let segs: Vec<&str> = trimmed.split('/').collect();
241	        match segs[0] {
242	            "robots.txt" if segs.len() == 1 => Toplevel::Robots,
243	            "favicon.ico" if segs.len() == 1 => Toplevel::Favicon,
244	            "kill" if segs.len() == 1 => Toplevel::Kill,
245	            "static" => Toplevel::Static(owned(&segs[1..])),
246	            "thy" => match Route::parse(path) {
247	                Some(r) => Toplevel::Thy(r),
248	                None => Toplevel::Other(path.to_string()),
249	            },
250	            _ => Toplevel::Other(path.to_string()),
251	        }
252	    }
253	}
254	
255	/// A parsed `autoprove/{strategy}/{bound}/{allSol}/proof/{lemma}[/path…]` request.
256	///
257	/// Observed variant matrix (corpus [Q030], keyboard help [Q031]): `strategy` is
258	/// `idfs` (solve/prove) or `characterize` (characterization, e.g. exists-trace);
259	/// `bound` is a depth bound (`0` = unbounded — the `a`/`A`/`s`/`S` shortcuts; `5`
260	/// = bounded — the `b`/`B` shortcuts); `all_solutions` is the `True`/`False` flag
261	/// (`False` = stop after the first solution, the lowercase shortcuts; `True` =
262	/// search for all solutions, the uppercase shortcuts).
263	#[derive(Debug, PartialEq, Eq, Clone)]
264	pub struct Autoprove {
265	    pub strategy: String,
266	    pub bound: u64,
267	    pub all_solutions: bool,
268	    pub lemma: String,
269	    pub path: Vec<String>,
270	}
271	
272	impl Autoprove {
273	    /// Parse the tail of an `autoprove/…` route (everything after `autoprove/`).
274	    pub fn parse(tail: &[String]) -> Option<Autoprove> {
275	        match tail {
276	            [strategy, bound, flag, proof, lemma, rest @ ..] if proof == "proof" => {
277	                Some(Autoprove {
278	                    strategy: strategy.clone(),
279	                    bound: bound.parse().ok()?,
280	                    all_solutions: parse_bool(flag)?,
281	                    lemma: lemma.clone(),
282	                    path: rest.to_vec(),
283	                })
284	            }
285	            _ => None,
286	        }
287	    }
288	}
289	
290	/// A parsed `autoproveDiff/{strategy}/{bound}/diffProof/{lemma}[/side…]` request
291	/// (observational-equivalence autoprove). Unlike [`Autoprove`], the diff form
292	/// carries **no** all-solutions flag (observed in the diff-proof body links).
293	#[derive(Debug, PartialEq, Eq, Clone)]
294	pub struct AutoproveDiff {
295	    pub strategy: String,
296	    pub bound: u64,
297	    pub lemma: String,
298	    pub path: Vec<String>,
299	}
300	
301	impl AutoproveDiff {
302	    /// Parse the tail of an `autoproveDiff/…` route.
303	    pub fn parse(tail: &[String]) -> Option<AutoproveDiff> {
304	        match tail {
305	            [strategy, bound, marker, lemma, rest @ ..] if marker == "diffProof" => {
306	                Some(AutoproveDiff {
307	                    strategy: strategy.clone(),
308	                    bound: bound.parse().ok()?,
309	                    lemma: lemma.clone(),
310	                    path: rest.to_vec(),
311	                })
312	            }
313	            _ => None,
314	        }
315	    }
316	}
317	
318	/// A parsed `autoproveAll/{strategy}/{bound}` request (autoprove every lemma).
319	#[derive(Debug, PartialEq, Eq, Clone)]
320	pub struct AutoproveAll {
321	    pub strategy: String,
322	    pub bound: u64,
323	}
324	
325	impl AutoproveAll {
326	    /// Parse the tail of an `autoproveAll/…` route.
327	    pub fn parse(tail: &[String]) -> Option<AutoproveAll> {
328	        match tail {
329	            [strategy, bound] => Some(AutoproveAll {
330	                strategy: strategy.clone(),
331	                bound: bound.parse().ok()?,
332	            }),
333	            _ => None,
334	        }
335	    }
336	}
337	
338	/// Navigation direction for `next`/`prev`.
339	#[derive(Debug, PartialEq, Eq, Clone, Copy)]
340	pub enum NavDir {
341	    Next,
342	    Prev,
343	}
344	
345	/// A parsed `next|prev/{mode}/proof/{lemma}` request. `mode` (`normal` observed;
346	/// the server also accepts other tokens and passes them to the prover) selects the
347	/// prover's traversal function.
348	#[derive(Debug, PartialEq, Eq, Clone)]
349	pub struct Nav {
350	    pub dir: NavDir,
351	    pub mode: String,
352	    pub lemma: String,
353	}
354	
355	impl Nav {
356	    pub fn parse(dir: NavDir, tail: &[String]) -> Option<Nav> {
357	        match tail {
358	            [mode, proof, lemma] if proof == "proof" => Some(Nav {
359	                dir,
360	                mode: mode.clone(),
361	                lemma: lemma.clone(),
362	            }),
363	            _ => None,
364	        }
365	    }
366	}
367	
368	/// The full-page `overview/*` views. `help` and `proof/…` appear in the crawl;
369	/// `edit/{name}` and `add/{pos}` appear only as POST-redirect (303) targets
370	/// (live [L12]).
371	#[derive(Debug, PartialEq, Eq, Clone)]
372	pub enum OverviewView {
373	    Help,
374	    Proof { lemma: String, path: Vec<String> },
375	    /// The diff-mode proof view (`overview/diffProof/{lemma}[/path…]`), the target
376	    /// of a `diffMethod`/`autoproveDiff` redirect.
377	    DiffProof { lemma: String, path: Vec<String> },
378	    Edit(String),
379	    Add(String),
380	    /// The delete-confirmation view (`overview/delete/{name}`), the target of a
381	    /// failed (lemma-not-found) delete.
382	    Delete(String),
383	    Other(Vec<String>),
384	}
385	
386	impl OverviewView {
387	    pub fn parse(tail: &[String]) -> OverviewView {
388	        match tail.iter().map(String::as_str).collect::<Vec<_>>().as_slice() {
389	            ["help"] => OverviewView::Help,
390	            ["proof", lemma, rest @ ..] => OverviewView::Proof {
391	                lemma: (*lemma).to_string(),
392	                path: rest.iter().map(|s| s.to_string()).collect(),
393	            },
394	            ["diffProof", lemma, rest @ ..] => OverviewView::DiffProof {
395	                lemma: (*lemma).to_string(),
396	                path: rest.iter().map(|s| s.to_string()).collect(),
397	            },
398	            ["edit", name] => OverviewView::Edit((*name).to_string()),
399	            ["add", pos] => OverviewView::Add((*pos).to_string()),
400	            ["delete", name] => OverviewView::Delete((*name).to_string()),
401	            _ => OverviewView::Other(tail.to_vec()),
402	        }
403	    }
404	}
405	
406	/// The structural-edit verb of a POST `edit/{verb}/{name}` form target
407	/// (live [L12]/[L13]).
408	#[derive(Debug, PartialEq, Eq, Clone)]
409	pub enum EditVerb {
410	    Edit,
411	    Add,
412	    Delete,
413	}
414	
415	impl EditVerb {
416	    pub fn parse(s: &str) -> Option<EditVerb> {
417	        match s {
418	            "edit" => Some(EditVerb::Edit),
419	            "add" => Some(EditVerb::Add),
420	            "delete" => Some(EditVerb::Delete),
421	            _ => None,
422	        }
423	    }
424	}
425	
426	fn parse_bool(s: &str) -> Option<bool> {
427	    match s {
428	        "True" => Some(true),
429	        "False" => Some(false),
430	        _ => None,
431	    }
432	}
