434	#[cfg(test)]
435	mod tests {
436	    use super::*;
437	
438	    #[test]
439	    fn parses_main_rules() {
440	        let r = Route::parse("/thy/trace/#/main/rules").unwrap();
441	        assert_eq!(r.theory_kind, "trace");
442	        assert_eq!(r.index, Index::Current);
443	        assert_eq!(r.handler, Handler::Main(Main::Rules));
444	    }
445	
446	    #[test]
447	    fn parses_cases_with_numbers() {
448	        let r = Route::parse("/thy/trace/1/main/cases/refined/0/2").unwrap();
449	        assert_eq!(r.index, Index::Num(1));
450	        assert_eq!(
451	            r.handler,
452	            Handler::Main(Main::Cases { refined: true, level: 0, n: 2 })
453	        );
454	    }
455	
456	    #[test]
457	    fn parses_proof_path() {
458	        let r = Route::parse("/thy/trace/3/main/proof/exec/_/B_2").unwrap();
459	        assert_eq!(
460	            r.handler,
461	            Handler::Main(Main::Proof {
462	                lemma: "exec".to_string(),
463	                path: vec!["_".to_string(), "B_2".to_string()],
464	            })
465	        );
466	    }
467	
468	    #[test]
469	    fn parses_method_and_dot_and_text() {
470	        assert_eq!(
471	            Route::parse("/thy/trace/#/main/method/exec/1").unwrap().handler,
472	            Handler::Main(Main::Method { lemma: "exec".to_string(), n: 1, path: vec![] })
473	        );
474	        assert_eq!(
475	            Route::parse("/thy/trace/3/main/method/exec/2/_/B_2").unwrap().handler,
476	            Handler::Main(Main::Method {
477	                lemma: "exec".to_string(),
478	                n: 2,
479	                path: vec!["_".to_string(), "B_2".to_string()],
480	            })
481	        );
482	        assert!(matches!(
483	            Route::parse("/thy/trace/#/interactive-graph-def/proof/exec").unwrap().handler,
484	            Handler::InteractiveGraphDef(_)
485	        ));
486	        assert_eq!(
487	            Route::parse("/thy/trace/#/source").unwrap().handler,
488	            Handler::Source
489	        );
490	    }
491	
492	    #[test]
493	    fn rejects_non_thy() {
494	        assert!(Route::parse("/static/css/x.css").is_none());
495	        assert!(Route::parse("/").is_none());
496	    }
497	
498	    #[test]
499	    fn parses_autoprove_variants() {
500	        let r = Route::parse("/thy/trace/1/autoprove/idfs/0/False/proof/types").unwrap();
501	        let tail = match r.handler {
502	            Handler::Autoprove(t) => t,
503	            _ => panic!("not autoprove"),
504	        };
505	        assert_eq!(
506	            Autoprove::parse(&tail).unwrap(),
507	            Autoprove {
508	                strategy: "idfs".into(),
509	                bound: 0,
510	                all_solutions: false,
511	                lemma: "types".into(),
512	                path: vec![],
513	            }
514	        );
515	        // characterize, bounded, all-solutions, with a path.
516	        let r = Route::parse("/thy/trace/1/autoprove/characterize/5/True/proof/L/_/B_2").unwrap();
517	        let tail = match r.handler {
518	            Handler::Autoprove(t) => t,
519	            _ => panic!(),
520	        };
521	        let ap = Autoprove::parse(&tail).unwrap();
522	        assert_eq!(ap.strategy, "characterize");
523	        assert_eq!(ap.bound, 5);
524	        assert!(ap.all_solutions);
525	        assert_eq!(ap.path, vec!["_".to_string(), "B_2".to_string()]);
526	    }
527	
528	    #[test]
529	    fn parses_nav_and_overview_views() {
530	        let r = Route::parse("/thy/trace/1/next/normal/proof/Client_auth").unwrap();
531	        if let Handler::Next(t) = r.handler {
532	            assert_eq!(
533	                Nav::parse(NavDir::Next, &t).unwrap(),
534	                Nav { dir: NavDir::Next, mode: "normal".into(), lemma: "Client_auth".into() }
535	            );
536	        } else {
537	            panic!();
538	        }
539	        assert_eq!(OverviewView::parse(&owned(&["help"])), OverviewView::Help);
540	        assert_eq!(
541	            OverviewView::parse(&owned(&["edit", "L"])),
542	            OverviewView::Edit("L".into())
543	        );
544	        assert_eq!(
545	            OverviewView::parse(&owned(&["proof", "L", "_", "B_2"])),
546	            OverviewView::Proof { lemma: "L".into(), path: vec!["_".into(), "B_2".into()] }
547	        );
548	    }
549	}
