249	/// The interactive server's state: the version map plus the monotonic next-index
250	/// counter. One global index namespace covers every loaded/derived theory-version.
251	pub struct Server<T: ProverOps> {
252	    ops: T,
253	    versions: BTreeMap<u64, T::Theory>,
254	    next_index: u64,
255	}
256	
257	impl<T: ProverOps> Server<T> {
258	    /// Create a server holding `base` as version 1.
259	    pub fn new(ops: T, base: T::Theory) -> Server<T> {
260	        let mut versions = BTreeMap::new();
261	        versions.insert(1, base);
262	        Server { ops, versions, next_index: 2 }
263	    }
264	
265	    /// Version indices currently allocated (ascending). All are resolvable.
266	    pub fn versions(&self) -> Vec<u64> {
267	        self.versions.keys().copied().collect()
268	    }
269	
270	    fn resolve(&self, index: &Index) -> Option<u64> {
271	        match index {
272	            Index::Num(v) if self.versions.contains_key(v) => Some(*v),
273	            _ => None,
274	        }
275	    }
276	
277	    fn commit_new_version(&mut self, thy: T::Theory) -> u64 {
278	        let new_index = self.next_index;
279	        self.next_index += 1;
280	        self.versions.insert(new_index, thy);
281	        new_index
282	    }
283	
284	    /// Dispatch a request across the whole surface, mutating version state as
285	    /// observed.
286	    pub fn dispatch(&mut self, req: &Request) -> Response {
287	        match Toplevel::parse(req.path) {
288	            Toplevel::Root => self.root(req),
289	            Toplevel::Robots => self.get_only(req, || Response::text(assets::ROBOTS_TXT.to_string())),
290	            Toplevel::Favicon => self.get_only(req, || Response::see_other(assets::FAVICON_TARGET.to_string())),
291	            Toplevel::Kill => self.kill(req),
292	            Toplevel::Static(segs) => self.static_asset(req, &segs),
293	            Toplevel::Thy(route) => self.thy(req, &route),
294	            Toplevel::Other(_) => Response::not_found(req.path),
295	        }
296	    }
297	
298	    /// Run `f` for a GET; a non-GET on a GET-only route answers `405`.
299	    fn get_only(&self, req: &Request, f: impl FnOnce() -> Response) -> Response {
300	        match req.method {
301	            HttpMethod::Get => f(),
302	            other => Response::bad_method(other),
303	        }
304	    }
305	
306	    // ---- top-level routes ------------------------------------------------
307	
308	    fn root(&mut self, req: &Request) -> Response {
309	        match req.method {
310	            HttpMethod::Get => Response::html(self.render_index(Flash::None)),
311	            HttpMethod::Post => {
312	                let uploaded = req.field("uploadedTheory");
313	                let loaded = if uploaded.is_empty() {
314	                    None
315	                } else {
316	                    self.ops.load_theory(uploaded)
317	                };
318	                match loaded {
319	                    Some(thy) => {
320	                        self.commit_new_version(thy);
321	                        Response::html(self.render_index(Flash::Loaded))
322	                    }
323	                    None => Response::html(self.render_index(Flash::PostFailed)),
324	                }
325	            }
326	        }
327	    }
328	
329	    /// Render the index page for the current version set. Rows are emitted in
330	    /// ascending index order; the reference server's exact row *ordering* and the
331	    /// per-row time/origin are non-deterministic (prover/environment concerns).
332	    fn render_index(&self, flash: Flash) -> String {
333	        let mut version = String::new();
334	        let mut rows: Vec<RootRow> = Vec::with_capacity(self.versions.len());
335	        // Owned strings must outlive the borrowed RootRow slice.
336	        let mut owned: Vec<(u64, String, String, bool, String)> = Vec::new();
337	        for (&idx, thy) in &self.versions {
338	            let m = self.ops.meta(thy);
339	            let rm = self.ops.root_meta(thy);
340	            if version.is_empty() {
341	                version = m.version.clone();
342	            }
343	            owned.push((idx, m.name, rm.time, rm.modified, rm.origin));
344	        }
345	        for (idx, name, time, modified, origin) in &owned {
346	            rows.push(RootRow { index: *idx, name, time, modified: *modified, origin });
347	        }
348	        page::render_root(flash, &version, &rows)
349	    }
350	
351	    fn kill(&self, req: &Request) -> Response {
352	        match req.method {
353	            HttpMethod::Get => match req.query_param("path") {
354	                Some(_) => Response::text(assets::KILL_CANCELED.to_string()),
355	                None => Response::invalid_args(&[assets::KILL_NO_PATH_MSG]),
356	            },
357	            other => Response::bad_method(other),
358	        }
359	    }
360	
361	    fn static_asset(&self, req: &Request, segs: &[String]) -> Response {
362	        match req.method {
363	            HttpMethod::Get => match self.ops.static_file(segs) {
364	                Some(bytes) => {
365	                    let joined = segs.join("/");
366	                    // Asset bytes are opaque environment data; a UTF-8 asset is
367	                    // reproduced exactly, a binary asset is streamed at integration.
368	                    let body = String::from_utf8_lossy(&bytes).into_owned();
369	                    Response::base(200, assets::static_content_type(&joined), body)
370	                }
371	                None => Response::static_missing(),
372	            },
373	            other => Response::bad_method(other),
374	        }
375	    }
376	
377	    // ---- theory-scoped routes -------------------------------------------
378	
379	    fn thy(&mut self, req: &Request, route: &Route) -> Response {
380	        let index = match self.resolve(&route.index) {
381	            Some(v) => v,
382	            None => return Response::not_found(req.path),
383	        };
384	        let kind = shell_kind(&route.theory_kind);
385	        match (req.method, &route.handler) {
386	            // Proof operations (allocate a new version) — intercept before reads.
387	            (HttpMethod::Get, Handler::Main(Main::Method { lemma, n, path })) => {
388	                self.proof_method(kind, index, &lemma.clone(), *n, &path.clone(), false)
389	            }
390	            (HttpMethod::Get, Handler::Main(Main::DiffMethod { lemma, n, path })) => {
391	                self.proof_method(kind, index, &lemma.clone(), *n, &path.clone(), true)
392	            }
393	            (HttpMethod::Get, Handler::Main(m)) => self.get_main(index, m),
394	            (HttpMethod::Get, Handler::Overview(tail)) => {
395	                self.get_overview(kind, index, &OverviewView::parse(tail))
396	            }
397	            (HttpMethod::Get, Handler::Autoprove(tail)) => match Autoprove::parse(tail) {
398	                Some(ap) => {
399	                    let (thy, focus) = self.ops.autoprove(&self.versions[&index], &ap);
400	                    let new = self.commit_new_version(thy);
401	                    Response::json(envelope::render_redirect(&overview_proof_path(kind, new, &ap.lemma, &focus, false)))
402	                }
403	                None => Response::not_found(req.path),
404	            },
405	            (HttpMethod::Get, Handler::AutoproveDiff(tail)) => match AutoproveDiff::parse(tail) {
406	                Some(ap) => {
407	                    let (thy, focus) = self.ops.autoprove_diff(&self.versions[&index], &ap);
408	                    let new = self.commit_new_version(thy);
409	                    Response::json(envelope::render_redirect(&overview_proof_path(kind, new, &ap.lemma, &focus, true)))
410	                }
411	                None => Response::not_found(req.path),
412	            },
413	            (HttpMethod::Get, Handler::AutoproveAll(tail)) => match AutoproveAll::parse(tail) {
414	                Some(ap) => {
415	                    let thy = self.ops.autoprove_all(&self.versions[&index], &ap);
416	                    let new = self.commit_new_version(thy);
417	                    Response::json(envelope::render_redirect(&format!("/thy/{}/{}/overview/help", kind.path(), new)))
418	                }
419	                None => Response::not_found(req.path),
420	            },
421	            (HttpMethod::Get, Handler::Next(tail)) => self.get_nav(index, NavDir::Next, tail, req.path),
422	            (HttpMethod::Get, Handler::Prev(tail)) => self.get_nav(index, NavDir::Prev, tail, req.path),
423	            (HttpMethod::Get, Handler::Source) | (HttpMethod::Get, Handler::Message) => {
424	                Response::text(self.ops.source_text(&self.versions[&index]))
425	            }
426	            (HttpMethod::Get, Handler::Download(_)) => {
427	                Response::octet(self.ops.source_text(&self.versions[&index]))
428	            }
429	            (HttpMethod::Get, Handler::Intdot(tail)) => self.get_intdot(kind, index, tail),
430	            (HttpMethod::Get, Handler::InteractiveGraphDef(tail)) => {
431	                Response::text(self.ops.graph_dot(&self.versions[&index], tail))
432	            }
433	            // Wrong method on GET-only theory routes.
434	            (HttpMethod::Post, Handler::Source)
435	            | (HttpMethod::Post, Handler::Message)
436	            | (HttpMethod::Post, Handler::Download(_)) => Response::bad_method(HttpMethod::Post),
437	
438	            // In-place mutating POSTs.
439	            (HttpMethod::Post, Handler::Reload) => {
440	                let new_thy = self.ops.reload(&self.versions[&index]);
441	                self.versions.insert(index, new_thy);
442	                Response::json(envelope::render_redirect(&format!("/thy/{}/{}/overview/help", kind.path(), index)))
443	            }
444	            (HttpMethod::Get, Handler::Reload) => Response::bad_method(HttpMethod::Get),
445	            (HttpMethod::Post, Handler::GetAndAppend(_)) => {
446	                Response::json(envelope::render_alert(&self.ops.append_message(&self.versions[&index])))
447	            }
448	            (HttpMethod::Get, Handler::GetAndAppend(_)) => Response::bad_method(HttpMethod::Get),
449	            (HttpMethod::Post, Handler::Edit(tail)) => self.post_edit(kind, index, tail, req),
450	            _ => Response::not_found(req.path),
451	        }
452	    }
453	
454	    // ---- GET main/* : JSON envelopes ----
455	    fn get_main(&self, index: u64, m: &Main) -> Response {
456	        let thy = &self.versions[&index];
457	        let content = match m {
458	            Main::Help => self.ops.main_content(thy, index, &MainReq::Help),
459	            Main::Message => self.ops.main_content(thy, index, &MainReq::Message),
460	            Main::Rules => self.ops.main_content(thy, index, &MainReq::Rules),
461	            Main::DiffRules => self.ops.main_content(thy, index, &MainReq::DiffRules),
462	            Main::Tactic => self.ops.main_content(thy, index, &MainReq::Tactic),
463	            Main::Cases { refined, level, n } => {
464	                self.ops.main_content(thy, index, &MainReq::Cases { refined: *refined, level: *level, n: *n })
465	            }
466	            Main::Lemma(name) => self.ops.main_content(thy, index, &MainReq::Lemma(name)),
467	            Main::Proof { lemma, path } => {
468	                self.ops.main_content(thy, index, &MainReq::Proof { lemma, path })
469	            }
470	            Main::DiffProof { lemma, path } => {
471	                self.ops.main_content(thy, index, &MainReq::DiffProof { lemma, path })
472	            }
473	            Main::Edit(name) => {
474	                let src = self.ops.lemma_source(thy, name).unwrap_or_default();
475	                Content { html: forms::edit_form(name, &src), title: format!("Edit Lemma: {name}") }
476	            }
477	            Main::Add(pos) => Content { html: forms::add_form(pos), title: "Add new Lemma".to_string() },
478	            Main::Delete(name) => Content { html: forms::delete_form(name), title: format!("Delete {name}") },
479	            // Proof ops are intercepted in `thy`; unreachable read-side.
480	            Main::Method { .. } | Main::DiffMethod { .. } => return Response::not_found("method"),
481	            Main::Other(_) => return Response::not_found("main"),
482	        };
483	        Response::json(envelope::render_content(&content.html, &content.title))
484	    }
485	
486	    // ---- GET overview/* : full-page HTML ----
487	    fn get_overview(&self, kind: ShellKind, index: u64, view: &OverviewView) -> Response {
488	        let thy = &self.versions[&index];
489	        let meta = self.ops.meta(thy);
490	        let west = self.ops.west_pane(thy, index);
491	        let center = self.center_for(thy, index, view);
492	        let params = PageParams {
493	            theory_name: &meta.name,
494	            index,
495	            version: &meta.version,
496	            filename: &meta.filename,
497	        };
498	        Response::html(page::render_page_kind(kind, &params, &west, &center))
499	    }
500	
501	    /// The center-pane inner HTML for an overview view: the corresponding `main/*`
502	    /// html **plus one trailing space** (BEHAVIOR §12).
503	    fn center_for(&self, thy: &T::Theory, index: u64, view: &OverviewView) -> String {
504	        let inner = match view {
505	            OverviewView::Help => self.ops.main_content(thy, index, &MainReq::Help).html,
506	            OverviewView::Proof { lemma, path } => {
507	                self.ops.main_content(thy, index, &MainReq::Proof { lemma, path }).html
508	            }
509	            OverviewView::DiffProof { lemma, path } => {
510	                self.ops.main_content(thy, index, &MainReq::DiffProof { lemma, path }).html
511	            }
512	            OverviewView::Edit(name) => {
513	                let src = self.ops.lemma_source(thy, name).unwrap_or_default();
514	                forms::edit_form(name, &src)
515	            }
516	            OverviewView::Add(pos) => forms::add_form(pos),
517	            OverviewView::Delete(name) => forms::delete_form(name),
518	            OverviewView::Other(_) => String::new(),
519	        };
520	        format!("{inner} ")
521	    }
522	
523	    // ---- GET next/prev : text/plain bare URL ----
524	    fn get_nav(&self, index: u64, dir: NavDir, tail: &[String], path: &str) -> Response {
525	        match Nav::parse(dir, tail) {
526	            Some(nav) => Response::text(self.ops.nav_target(&self.versions[&index], index, dir, &nav.mode, &nav.lemma)),
527	            None => Response::not_found(path),
528	        }
529	    }
530	
531	    // ---- GET intdot : html mini page (handler swapped intdot -> i-g-def) ----
532	    fn get_intdot(&self, kind: ShellKind, index: u64, tail: &[String]) -> Response {
533	        let meta = self.ops.meta(&self.versions[&index]);
534	        let trailing = tail.join("/");
535	        let dotsrc = format!("/thy/{}/{}/interactive-graph-def/{}", kind.path(), index, trailing);
536	        Response::html(intdot::render_intdot(&meta.name, &dotsrc))
537	    }
538	
539	    // ---- proof operations: new version + JSON {redirect}, or {alert} on failure ----
540	    fn proof_method(&mut self, kind: ShellKind, index: u64, lemma: &str, n: usize, path: &[String], diff: bool) -> Response {
541	        let applied = if diff {
542	            self.ops.apply_diff_method(&self.versions[&index], lemma, n, path)
543	        } else {
544	            self.ops.apply_method(&self.versions[&index], lemma, n, path)
545	        };
546	        match applied {
547	            Some((new_thy, focus)) => {
548	                let new = self.commit_new_version(new_thy);
549	                Response::json(envelope::render_redirect(&overview_proof_path(kind, new, lemma, &focus, diff)))
550	            }
551	            None => Response::json(envelope::render_alert(METHOD_FAILED_ALERT)),
552	        }
553	    }
554	
555	    // ---- structural POST: mutate in place; 303 (or 200 form on edit/add failure) ----
556	    fn post_edit(&mut self, kind: ShellKind, index: u64, tail: &[String], req: &Request) -> Response {
557	        let (verb, name) = match tail {
558	            [v, n] => match EditVerb::parse(v) {
559	                Some(verb) => (verb, n.clone()),
560	                None => return Response::not_found(req.path),
561	            },
562	            _ => return Response::not_found(req.path),
563	        };
564	        let k = kind.path();
565	        match verb {
566	            EditVerb::Delete => match self.ops.delete_lemma(&self.versions[&index], &name) {
567	                Some(new_thy) => {
568	                    self.versions.insert(index, new_thy);
569	                    Response::see_other(format!("/thy/{k}/{index}/overview/help"))
570	                }
571	                // Lemma not found: theory unchanged, redirect to the delete view.
572	                None => Response::see_other(format!("/thy/{k}/{index}/overview/delete/{name}")),
573	            },
574	            EditVerb::Edit => {
575	                let text = req.field("lemma-text");
576	                match self.ops.edit_lemma(&self.versions[&index], &name, text) {
577	                    Some(new_thy) => {
578	                        self.versions.insert(index, new_thy);
579	                        Response::see_other(format!("/thy/{k}/{index}/overview/edit/{name}"))
580	                    }
581	                    None => self.get_overview(kind, index, &OverviewView::Edit(name)),
582	                }
583	            }
584	            EditVerb::Add => {
585	                let text = req.field("lemma-text");
586	                match self.ops.add_lemma(&self.versions[&index], &name, text) {
587	                    Some(new_thy) => {
588	                        self.versions.insert(index, new_thy);
589	                        Response::see_other(format!("/thy/{k}/{index}/overview/add/{name}"))
590	                    }
591	                    None => self.get_overview(kind, index, &OverviewView::Add(name)),
592	                }
593	            }
594	        }
595	    }
596	
597	    /// Apply a proof method that arrived as a parsed `Main::Method`. Exposed so a
598	    /// caller that pre-parses `main/method` can drive the version bump directly.
599	    pub fn apply_main_method(&mut self, index: u64, lemma: &str, n: usize, path: &[String]) -> Response {
600	        self.proof_method(ShellKind::Trace, index, lemma, n, path, false)
601	    }
602	}
603	
604	/// Map a URL theory-kind segment to a shell variant.
605	fn shell_kind(kind: &str) -> ShellKind {
606	    match kind {
607	        "equiv" => ShellKind::Equiv,
608	        _ => ShellKind::Trace,
609	    }
610	}
611	
612	/// Build the redirect target for a proof operation: an `overview/proof/…` URL for
613	/// trace, or `overview/diffProof/…` for diff, at version `index`.
614	fn overview_proof_path(kind: ShellKind, index: u64, lemma: &str, focus: &[String], diff: bool) -> String {
615	    let handler = if diff { "diffProof" } else { "proof" };
616	    let mut s = format!("/thy/{}/{}/overview/{}/{}", kind.path(), index, handler, lemma);
617	    for seg in focus {
618	        s.push('/');
619	        s.push_str(seg);
620	    }
621	    s
622	}
