1	//! JSON response envelopes for the `main/*` (and `method/*`, `autoprove/*`)
2	//! AJAX handlers.
3	//!
4	//! Observed: every `kind=json` response body is one of three compact JSON
5	//! objects, with keys in this order and no insignificant whitespace:
6	//!   * content:  `{"html":<string>,"title":<string>}`
7	//!   * redirect: `{"redirect":<string>}`
8	//!   * alert:    `{"alert":<string>}`   (a client-side popup message: a failed
9	//!     proof-method application, or the `get_and_append` confirmation)
10	//!
11	//! There is no trailing newline. Non-ASCII is emitted as literal UTF-8 (no
12	//! `\uXXXX`), and `/ < > &` are NOT backslash/entity escaped inside the JSON
13	//! string — i.e. standard JSON string escaping (only `" \` and control chars).
14	//! `serde_json`'s default serialization reproduces this exactly.
15	
16	use serde::Serialize;
17	
18	/// A content pane response: rendered HTML plus the pane title.
19	#[derive(Serialize)]
20	pub struct Content<'a> {
21	    pub html: &'a str,
22	    pub title: &'a str,
23	}
24	
25	/// A redirect response instructing the client to navigate to `redirect`.
26	#[derive(Serialize)]
27	pub struct Redirect<'a> {
28	    pub redirect: &'a str,
29	}
30	
31	/// An alert response: a message the client shows as a popup.
32	#[derive(Serialize)]
33	pub struct Alert<'a> {
34	    pub alert: &'a str,
35	}
36	
37	/// Serialize `{"html":..,"title":..}` exactly as the web layer does.
38	pub fn render_content(html: &str, title: &str) -> String {
39	    serde_json::to_string(&Content { html, title }).expect("Content serializes")
40	}
41	
42	/// Serialize `{"redirect":..}` exactly as the web layer does.
43	pub fn render_redirect(path: &str) -> String {
44	    serde_json::to_string(&Redirect { redirect: path }).expect("Redirect serializes")
45	}
46	
47	/// Serialize `{"alert":..}` exactly as the web layer does.
48	pub fn render_alert(message: &str) -> String {
49	    serde_json::to_string(&Alert { alert: message }).expect("Alert serializes")
50	}
51	
52	/// The fixed alert emitted when a proof-method application fails.
53	pub const METHOD_FAILED_ALERT: &str = "Sorry, but the prover failed on the selected method!";
54	
55	#[cfg(test)]
56	mod tests {
57	    use super::*;
58	
59	    #[test]
60	    fn content_envelope_shape() {
61	        assert_eq!(
62	            render_content("this is a mistake<br/>\n", "Lemma: exec"),
63	            r#"{"html":"this is a mistake<br/>\n","title":"Lemma: exec"}"#
64	        );
65	    }
66	
67	    #[test]
68	    fn redirect_envelope_shape() {
69	        assert_eq!(
70	            render_redirect("/thy/trace/4/overview/proof/exec/_"),
71	            r#"{"redirect":"/thy/trace/4/overview/proof/exec/_"}"#
72	        );
