76	    fn keeps_literal_utf8_and_unescaped_angle_brackets() {
77	        let s = render_content("<span>∃</span>", "t");
78	        assert!(s.contains("<span>∃</span>"), "got {s}");
79	        assert!(!s.contains("\\u"), "should not \\u-escape: {s}");
80	    }
81	}
